#ifndef CAN_BUS_H
#define CAN_BUS_H
#include <mcp_can.h>
void can_setup();
void can_loop();
bool can_send(uint32_t id, uint8_t* data, uint8_t len);
typedef void (*can_rx_cb)(uint32_t id, uint8_t* data, uint8_t len);
void can_on_receive(can_rx_cb cb);
#endif

firmware_template.source:
#include "can_bus.h"
#include <SPI.h>
static MCP_CAN can(5);
static can_rx_cb _rx=nullptr;
void can_setup(){
  if(can.begin(MCP_ANY,CAN_500KBPS,MCP_8MHZ)!=CAN_OK){Serial.println("[can] Init failed!");return;}
  can.setMode(MCP_NORMAL);pinMode(4,INPUT);Serial.println("[can] OK 500kbps");
}
void can_loop(){
  if(!digitalRead(4)){uint32_t id;uint8_t len;uint8_t buf[8];
    can.readMsgBuf(&id,&len,buf);if(_rx)_rx(id,buf,len);}
}
bool can_send(uint32_t id,uint8_t*d,uint8_t l){return can.sendMsgBuf(id,0,l,d)==CAN_OK;}
void can_on_receive(can_rx_cb cb){_rx=cb;}
